#include <stdio.h>
int main() {
    char s[100001];
    scanf("%s", s);
    int n = 0;
    while (s[n] != '\0') n++;
    int count = 0;
    for (int i = 0; i < n; i++) {
        if (s[i] != '\0') {
            count++;
            for (int j = i + 1; j < n; j++) {
                if (s[j] == s[i]) s[j] = '\0';
            }
        }
    }
    printf("%d\n", count);
    return 0;
}

