code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        String s = scanner.next();
        int n = s.length();
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) != '\0') {
                count++;
                for (int j = i + 1; j < n; j++) {
                    if (s.charAt(j) == s.charAt(i)) s = s.substring(0, j) + '\0' + s.substring(j + 1);
                }
            }
        }
        System.out.println(count);
    }
}

