const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
readline.on('line', (s) => {
    let count = 0;
    for (let i = 0; i < s.length; i++) {
        if (s[i] !== '\0') {
            count++;
            for (let j = i + 1; j < s.length; j++) {
                if (s[j] === s[i]) s = s.substring(0, j) + '\0' + s.substring(j + 1);
            }
        }
    }
    console.log(count);
});

